 1→{
 2→  "name": "system-spec-harness",
 3→  "version": "0.1.0",
 4→  "description": "カテゴリ×プラットフォームの網羅マトリクス、公式出典、独立完成度評価を用いてシステム仕様書を生成するハーネス plugin。",
 5→  "author": {
 6→    "name": "harness maintainers"
 7→  },
 8→  "hooks": "./hooks/hooks.json"
 9→}
10→

 1→{
 2→  "description": "dev-graph shared hooks; project settings fallback must not be enabled at the same time",
 3→  "hooks": {
 4→    "PreToolUse": [{
 5→      "matcher": "Bash",
 6→      "hooks": [{"type": "command", "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/hooks/guard-graph-schema.py\" --repo-root \"${CLAUDE_PROJECT_DIR}\"", "timeout": 10}]
 7→    }],
 8→    "SessionStart": [{
 9→      "matcher": "startup|resume",
10→      "hooks": [{"type": "command", "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/hooks/reconcile-task-lifecycle.py\" --event session-start --repo-root \"${CLAUDE_PROJECT_DIR}\"", "timeout": 10}]
11→    }],
12→    "PostToolUse": [{
13→      "matcher": "Bash",
14→      "hooks": [{"type": "command", "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/hooks/reconcile-task-lifecycle.py\" --event post-tool-use --repo-root \"${CLAUDE_PROJECT_DIR}\"", "timeout": 10, "async": true}]
15→    }],
16→    "TaskCompleted": [{
17→      "hooks": [{"type": "command", "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/hooks/reconcile-task-lifecycle.py\" --event task-completed --repo-root \"${CLAUDE_PROJECT_DIR}\"", "timeout": 20}]
18→    }]
19→  }
20→}
21→

 1→{
 2→  "description": "Protect confirmed system-spec chapters and the canonical spec state from unsafe mutation.",
 3→  "hooks": {
 4→    "PreToolUse": [
 5→      {
 6→        "matcher": "Write|Edit|MultiEdit|Bash",
 7→        "hooks": [
 8→          {
 9→            "type": "command",
10→            "command": "python3 \"${CLAUDE_PLUGIN_ROOT}/hooks/guard-confirmed-chapter-overwrite.py\"",
11→            "timeout": 10
12→          }
13→        ]
14→      }
15→    ]
16→  }
17→}
18→

